---req
function ModelQuest:OnQuestListReq(type)
    local pb = LProtoHelper.CreateProto(LProtoIds.QuestListReq)
    pb.type = type
    SendMessage(pb,LProtoIds.QuestListReq)
end

function ModelQuest:OnQuestReceiveReq(refId)

    local funcId = 11502000
    local list = {}
    if gModelFunctionOpen:CheckIsOpened(funcId) then
        local ref = self:GetTaskConfig(refId)
        if not ref then
            return
        end
        local type = ref.type
        local typeMap = self._acquireMap[type]
        if typeMap then
            local questList = self:GetQuestDataList()
            if not questList then
                return
            end

            for k,v in pairs(questList) do
                local taskType = v:GetType()
                if typeMap[taskType] then
                    if v:GetState() == ModelQuest.TASK_FINNISH then
                        table.insert(list,k)
                    end
                end
            end
        else
            table.insert(list,refId)
        end
    else
        table.insert(list,refId)
    end
    self:OnQuestReceiveReqInternal(list)

    for k,v in ipairs(list) do
        local data = self:GetTaskDataByRefId(v)
        if data then
            data:SetState(ModelQuest.TASK_REWARDED)
        end
    end

end

function ModelQuest:OnQuestReceiveReqInternal(refIds)
    local pb = LProtoHelper.CreateProto(LProtoIds.QuestReceiveReq)
    for k,v in ipairs(refIds) do
        pb.refId:append(v)
    end
    SendMessage(pb,LProtoIds.QuestReceiveReq)
end

