function ModelQuest:OnQuestListResp(pb)
    local outFinishedList = {}
    for k,v in ipairs(pb.addList) do
        self:RefreshQuestData(v, outFinishedList)
    end
    for k,v in ipairs(pb.updateList) do
        self:RefreshQuestData(v, outFinishedList)
    end

    local questList = self:GetQuestDataList()
    for k,v in ipairs(pb.removeList) do
        questList[v]= nil
    end

    FireEvent(EventNames.ON_QUEST_CHANGE, outFinishedList)
    gModelGeneral:CheckShowFinishTip()
end

function ModelQuest:OnQuestReceiveResp(pb)

end

function ModelQuest:RefreshQuestData(data, outFinishList)

    --地区屏蔽
    if gModelFunctionOpen:CheckRefDisable(ModelFunctionOpen.QUEST,data.refId) then
        return
    end

    local cfg = self:GetTaskConfig(data.refId)
    if not cfg then
        return
    end
    local task = StructTask:New()
    task:CreateByPb(data)

    local type = cfg.type
    local typeCfg = GameTable.MissionClassifyRef[type]
    local needTip = typeCfg and typeCfg.finishTips == 1


    local questDataList = self:GetQuestDataList()

    local finishList = {}
    if needTip then
        local oldData = questDataList[data.refId]
        if oldData then
            local oldState =  oldData:GetState()

            local newState = task:GetState()

            if oldState == 0 and newState == 1 then
                local title = string.replace(ccClientText(12216),ccLngText(typeCfg.title))
                local data =
                {
                    title = title,
                    desc = ccLngText(cfg.description),
                    jumpId = typeCfg.functionOpenRefId,
                }

                --table.insert(self._finishTipList,data)

                gModelGeneral:AddShowFinishTips(data)

                --self:CheckPopRating(type)

                table.insert(finishList,task:GetRefId())

                table.insert(outFinishList, task:GetRefId())
            end
        end
    end

    task:SetType(type)
    task:SetSort(cfg.sort)
    questDataList[data.refId]= task

    FireEvent(EventNames.ON_TASK_FINISH,finishList)
end

function ModelQuest:OnQuestFinishedResp(pb)
    if not self._finishQuestList then
        self._finishQuestList = {}
    end

    local curChange = {}
    for k,v in ipairs(pb.questRefId) do
        self._finishQuestList[v] = true
        table.insert(curChange,v)
    end
    FireEvent(EventNames.ON_TASK_FINISH,curChange)
end

