function ModelQuest:GetTaskTypeList()
    local t ={}

    local prio =
    {
        [1] = 3,
        [2] = 1,
        [3] = 2,
    }
    for k,v in ipairs(GameTable.MissionClassifyRef) do
        if v.frontEnd ==1 then
            local funcId = v.functionOpenRefId
            local isShow = gModelFunctionOpen:CheckIsShow(funcId)
            if isShow then
                table.insert(t,v.refId)
            end
        end

    end
    table.sort(t,function (a,b) return prio[a]<prio[b] end)
    return t
end

function ModelQuest:GetRewardList(refId)
    local dataList = {}

    local tempMap = {}
    local fixReward = self:GetQuestRewardByRefId(refId) or {} -- self._questRewards[refId]
    for k,v in ipairs(fixReward) do
        local tempData = tempMap[v.itemId]
        if not tempData then
            local data =
            {
                itemId = v.itemId,
                itemNum = v.itemNum,
                itemType = v.itemType,
            }
            table.insert(dataList,data)
            tempMap[v.itemId] = data
        else
            tempData.itemNum = tempData.itemNum + v.itemNum
        end

    end

    local taskData = self:GetTaskDataByRefId(refId)
    if taskData then
        local extraReward = taskData:GetReward()

        for k,v in ipairs(extraReward) do
            local tempData = tempMap[v.itemId]
            if not tempData then
                local data =
                {
                    itemId = v.itemId,
                    itemNum = tonumber(v.count),
                    itemType = v.type,
                }
                table.insert(dataList,data)
                tempMap[v.itemId] = data
            else
                tempData.itemNum = tempData.itemNum + v.count
            end

        end
    end

    return dataList
end

