function ModelQuest:GetTaskConfig(refId)
    local ref = self:GetModelConfig(ModelQuest.MissionRef)
    local cfg = ref[refId]
    if not cfg then
        printErrorN(string.format("no cfg GameTable.MissionRef refId %s",refId))
    end
