function ModelQuest:GetTaskDescByRefId(refId)
    local cfg = self:GetTaskConfig(refId)
    if cfg then
        return ccLngText(cfg.description)
    end
    return ""
end

function ModelQuest:GetTaskListByType(type)
    local t = {}
    local list = self:GetQuestDataList()
    for k,v in pairs(list) do
        if v:GetType() == type then
            table.insert(t,v)
        end
    end
    local comp = function(a,b)
        local aState = a:GetState()
        local aPrio = self:GetStatePrio(aState)
        local bState = b:GetState()
        local bPrio = self:GetStatePrio(bState)

        if aPrio~=bPrio then
            return aPrio<bPrio
        else
            return a:GetSort() < b:GetSort()
        end
    end

    table.sort(t,comp)
    return t
end

function ModelQuest:GetTaskKeyList(type)
    local t = {}
    local list = self:GetQuestDataList()
    for k,v in pairs(list) do
        if v:GetType() == type then
            table.insert(t,v)
        end
    end
    local list = {}
    for i, v in ipairs(t) do
        list[v._refId] = v
    end
    return list
end

---配置表里的任务列表分类
function ModelQuest:GetTaskCfgListByType(tType)
    local taskCfgList = self._taskCfgListT
    if not taskCfgList then
        taskCfgList = {}
        self._taskCfgListT = taskCfgList
        local refList = self:GetModelConfig(ModelQuest.MissionRef)
        for k,v in pairs(refList) do
            local taskType = v.type
            local typeList = taskCfgList[taskType]
            if not typeList then
                typeList = {}
                taskCfgList[taskType] = typeList
            end
            local taskData = StructTask:New()
            taskData:CreateByCfg(v)
            table.insert(typeList, taskData)
        end
    end

    local typeList = taskCfgList[tType]
    if not typeList then return end

    if not self._taskCfgSortFlagMap then
        self._taskCfgSortFlagMap = {}
    end

    if not self._taskCfgSortFlagMap[tType] then
        table.sort(typeList, function(a,b) return a:GetSort()<b:GetSort() end)
        self._taskCfgSortFlagMap[tType] = true
    end

    return typeList
end

function ModelQuest:GetTaskList(type)
    local t = {}

    local bSortCfg = true
    local questDataList = self:GetQuestDataList()
    if self._includeUnlock[type] then
        local tmpList = self:GetTaskCfgListByType(type) or {}
        for k,taskData in ipairs(tmpList) do
            local refId = taskData:GetRefId()
            local serverTaskData = questDataList[refId]
            if not serverTaskData then
                if type == ModelQuest.TYPE_152 then
                    taskData._state = ModelQuest.TASK_REWARDED
                end
                table.insert(t, taskData)
            else
                table.insert(t, serverTaskData)
            end
        end
        bSortCfg = false --列表已经按照配置的sort排好序的，如果不需要按排状态排序就不用排了
    else
        for k,v in pairs(questDataList) do
            if v:GetType() == type then
                table.insert(t,v)
            end
        end
    end

    local bSortState = self._sortByState[type]
    if bSortState then
        table.sort(t,function(a,b)
            local aState = a:GetState()
            local aPrio = self:GetStatePrio(aState)
            local bState = b:GetState()
            local bPrio = self:GetStatePrio(bState)

            if aPrio~=bPrio then
                return aPrio<bPrio
            else
                return a:GetSort() < b:GetSort()
            end
        end)
    elseif bSortCfg then
        table.sort(t, function(a,b) return a:GetSort()<b:GetSort() end)
    end

    return t
end

--服务器数据列表任务分类列表
function ModelQuest:GetTaskListByTypeList(typeList)
    local t = {}
    local list = self:GetQuestDataList()
    for k,v in pairs(list) do
        for i, n in pairs(typeList) do
            local type=n
            if v:GetType() == type then
                table.insert(t,v)
            end
        end
    end

    local comp = function(a,b)
        local aState = a:GetState()
        local aPrio = self:GetStatePrio(aState)
        local bState = b:GetState()
        local bPrio = self:GetStatePrio(bState)

        if aPrio~=bPrio then
            return aPrio<bPrio
        else
            return a:GetSort() < b:GetSort()
        end
    end

    table.sort(t,comp)
    return t
end

-- 返回列表的 key值 为 refId
function ModelQuest:GetTaskListKeyRefId(type)
    local t = {}
    local list = self:GetQuestDataList()
    for k,v in pairs(list) do
        if v:GetType() == type then
            local refId = v:GetRefId()
            t[refId] = v
        end
    end
    return t
end

function ModelQuest:GetStatePrio(state)
    if state == ModelQuest.TASK_UNFINISH then
        return 1
    elseif state == ModelQuest.TASK_FINNISH then
        return 0
    elseif state == ModelQuest.TASK_REWARDED then
        return 3
    elseif state == ModelQuest.TASK_LOCK then
        return 2
    end

end
function ModelQuest:GetTaskDataByRefId(refId)
    local list = self:GetQuestDataList()
    local data = list[refId]
    return data
end

function ModelQuest:TaskGoto(taskId,wndname)
    local cfg = self:GetTaskConfig(taskId)
    if not cfg then
        return false,false
    end
    local functionId = cfg.originId
    if functionId > 0 then
        local isOpen = gModelFunctionOpen:CheckIsOpened(functionId,true)
        if not isOpen then
            return false,true
        end
        gModelFunctionOpen:Jump(functionId,wndname)
        return true,true
    end
    return false,false
end
