function ModelQuest:GetQuestRewardByRefId(refId)
    local value = self:GetCacheValueByKey(ModelQuest.MissionRef,refId,"reward")
    if value then
        return value
    end
    local ref = self:GetTaskConfig(refId)
    if ref then
        value = ref.reward
        value = LxDataHelper.ParseItem(value)
        self:SetCacheValueByKey(ModelQuest.MissionRef,refId,"reward")
    end

    return value
end

