function ModelQuest:IsHaveFinishTaskByType(taskType)
	local questDataList = self:GetQuestDataList()
	local finishState = ModelQuest.TASK_FINNISH
	for k,v in pairs(questDataList) do
		if v:GetType() == taskType and v:GetState() == finishState then
			return true
		end
	end
	return false
end

---红点
function ModelQuest:CheckShowMainQuestRed()
    return self:IsHaveFinishTaskByType(ModelQuest.MAIN)
end

function ModelQuest:CheckShowDailyQuestRed()
    local isHave = self:IsHaveFinishTaskByType(ModelQuest.DAILY)
    if isHave then return true end

    isHave = self:IsHaveFinishTaskByType(ModelQuest.DAILY_BOX)
	if isHave then return true end
    return false
end

function ModelQuest:CheckShowWeekQuestRed()
    local isHave = self:IsHaveFinishTaskByType(ModelQuest.WEEK)
	if isHave then return true end

	isHave = self:IsHaveFinishTaskByType(ModelQuest.WEEK_BOX)
    if isHave then return true end

    return false
end

function ModelQuest:CheckShowQuestRed(taskTypeList)
    for k,v in ipairs(taskTypeList) do
        local isHave = self:IsHaveFinishTaskByType(v)
        if isHave then return true end
    end
    return false
end

function ModelQuest:CheckShowPassERed(sid)
    if not sid then
        local list = gModelActivity:GetActivityDataByModelId(ModelActivity.MODEL_PASSE)
        local startTime
        local activity
        for k,v in ipairs(list) do
            local curStartTime = v.startTime
            if not startTime or startTime < curStartTime then
                startTime = curStartTime
                activity = v
            end
        end

        local haveAct = activity ~= nil
        if not haveAct then
            return false
        end

        sid = activity.sid
    end

    local data = gModelRedPoint: GetActRedPointMap(sid)
    if not data then
        return false
    end

    local pageIdMap = data.pageIdMap or {}
    for k,v in pairs(pageIdMap) do
        if v == true and (k == ModelActivity.PASS_E_ELITE
                or k == ModelActivity.PASS_E_ADVANCE
                or k ==ModelActivity.PASS_E_SUPER)  then
            return true
        end
    end

    return false
end

function ModelQuest:GetShowType()
    local defaultType = ModelQuest.DAILY
    if self:CheckShowDailyQuestRed() then
        defaultType = ModelQuest.DAILY
    elseif self:CheckShowWeekQuestRed() then
        defaultType = ModelQuest.WEEK
    elseif self:CheckShowMainQuestRed() then
        defaultType = ModelQuest.MAIN
    end
    return defaultType
end

