function ModelQuest:IsTaskFinish(taskId)
    local questList = self:GetQuestDataList()
    local data = questList[taskId]
    if data and data:GetState() >= ModelQuest.TASK_FINNISH then
        return true
    end

    if self._finishQuestList  and self._finishQuestList[taskId] then
        return true
    end


end

function ModelQuest:GetTaskTypeRef(tType)
    local typeCfg = GameTable.MissionClassifyRef[tType]

    return typeCfg
end

function ModelQuest:OnClickTaskBtn(itemdata,wndName)
    local refId = itemdata:GetRefId()
    local state = itemdata:GetState()
    local cfg = gModelQuest:GetTaskConfig(refId)
    if state == ModelQuest.TASK_UNFINISH then
        local originId = cfg.originId
        if originId > 0 then
            gModelQuest:TaskGoto(refId,wndName)
        else
            GF.ShowMessage(ccClientText(12210))
        end
    elseif state== ModelQuest.TASK_FINNISH then
        itemdata:SetState(ModelQuest.TASK_REWARDED)
        gModelQuest:OnQuestReceiveReq(refId)
    elseif state == ModelQuest.TASK_REWARDED then
        GF.ShowMessage(ccClientText(12211))
    end
end

