function ModelQuest:GetQuestDataList()
    if not self._questDataList then
        ---@type StructTask[]
        self._questDataList = {}
    end
    return self._questDataList
end

---@return V_QuestRef[]
function ModelQuest:GetInviteFriendCfgs()
    ---@type V_QuestRef[]
    local initInviteFriendCfgs = self._initInviteFriendCfgs
    if not initInviteFriendCfgs then
        initInviteFriendCfgs = {}
        local questType = ModelQuest.TYPE_190
        ---@type table<number,V_QuestRef>
        local refs = self:GetModelConfig(ModelQuest.MissionRef)
        for refId,ref in pairs(refs) do
            if ref.type == questType then
                table.insert(initInviteFriendCfgs,ref)
            end
        end
        table.sort(initInviteFriendCfgs,function(a,b) return a.sort < b.sort end)
        self._initInviteFriendCfgs = initInviteFriendCfgs
    end
    return initInviteFriendCfgs
end


function ModelQuest:GetInviteFriendTakes()
    local list = {}
    local finishState = ModelQuest.TASK_REWARDED
    local initInviteFriendCfgs = self:GetInviteFriendCfgs()
    for i,v in ipairs(initInviteFriendCfgs) do
        local refId = v.refId
        local taskData = self:GetTaskDataByRefId(refId)
        if not taskData then
            local finishCond = string.split(v.finishCond,"=")
            local goal = checknumber(finishCond[3])
            taskData = StructTask:New()
            taskData:CreateByPb({
                refId = refId,
                state = finishState,
                finishCount = 1,
                items = {},
                schedule = goal,
                goal = goal,
                multiple = 0,
            })
        end
        table.insert(list,{
            reward = self:GetQuestRewardByRefId(refId),
            refId = refId,
            serverData = taskData,
            state = taskData:GetState(),
            cfg = v,
            sort = v.sort,
        })
    end
    return list
end

function ModelQuest:CheckIntiveFriendOpen()
    local isOpen = false
    if gLSdkImpl:CallMethod(LSdkMethod.IsSupportInviteFriend) then
        isOpen = true
    end

    if not isOpen then return false end

    local list = self:GetInviteFriendTakes()
    local taskCnt = #list
    if taskCnt < 1 then return false end

    local finishCnt = 0
    local finishState = ModelQuest.TASK_REWARDED
    for i,v in ipairs(list) do
        if v.state == finishState then
            finishCnt = finishCnt + 1
        end
    end
    return taskCnt > finishCnt
end

function ModelQuest:CheckHasIntiveFriendRP()
    if not self:CheckIntiveFriendOpen() then return false end

    local state = ModelQuest.TASK_FINNISH
    local list = self:GetInviteFriendTakes()
    for i,v in ipairs(list) do
        if v.state == state then
            return true
        end
    end
    return false
end

